mapper.sql:
scoped_ownership AS ( SELECT op.opid, op.uid, op.room_id, op.build_area, op.is_voting_delegate, COALESCE(roster.room_name, op.room_id::TEXT) AS room_name FROM c_owner_property op LEFT JOIN LATERAL ( SELECT pr.room_name, pr.unit_name FROM c_property_roster pr WHERE pr.tenant_id = op.tenant_id AND pr.room_id = op.room_id AND pr.status = 'ACTIVE' ORDER BY pr.roster_id LIMIT 1 ) roster ON TRUE WHERE op.tenant_id = #{tenantId} AND op.building_id = #{buildingId} AND op.account_status = 1 AND op.room_id IS NOT NULL
AND roster.unit_name = #{unitName}
), ranked_room_ownership AS ( SELECT ownership.*, ROW_NUMBER() OVER ( PARTITION BY ownership.room_id ORDER BY ownership.is_voting_delegate DESC, ownership.opid ) AS room_rank FROM scoped_ownership ownership ), represented_rooms AS ( SELECT uid, room_id, room_name, build_area FROM ranked_room_ownership WHERE room_rank = 1 ), decision_participants AS ( SELECT uid, MIN(room_id) AS room_id, STRING_AGG(room_name, '、' ORDER BY room_id) AS room_label, SUM(build_area)::NUMERIC(14, 2) AS build_area FROM represented_rooms GROUP BY uid )

mapper.insert:
INSERT INTO t_repair_local_decision (
    work_order_id, tenant_id, building_id, scope_type, decision_channel, unit_name, scope_label,
    total_owner_count, total_area, result
) VALUES (
    #{workOrderId}, #{tenantId}, #{buildingId}, #{scopeType}, #{decisionChannel}, #{unitName}, #{scopeLabel},
    #{totalOwnerCount}, #{totalArea}, #{result}
)

mapper.select:
SELECT decision.decision_id, work_order.work_order_id, work_order.order_no, work_order.title, work_order.location_text, work_order.survey_summary, decision.scope_label, MIN(property.opid) AS opid, MIN(property.room_id) AS room_id, STRING_AGG(COALESCE(roster.room_name, property.room_id::TEXT), '、' ORDER BY property.room_id) AS room_name, SUM(property.build_area)::NUMERIC(14, 2) AS build_area, quote.supplier_name, quote.quote_amount, quote.quote_summary, quote.attachment_id AS quote_attachment_id, entry.choice AS my_choice FROM t_repair_local_decision decision JOIN t_repair_work_order work_order ON work_order.work_order_id = decision.work_order_id AND work_order.tenant_id = decision.tenant_id JOIN c_owner_property property ON property.tenant_id = decision.tenant_id AND property.building_id = decision.building_id AND property.uid = #{uid} AND property.account_status = 1 AND property.opid = ( SELECT representative.opid FROM c_owner_property representative WHERE representative.tenant_id = property.tenant_id AND representative.building_id = property.building_id AND representative.room_id = property.room_id AND representative.account_status = 1 ORDER BY representative.is_voting_delegate DESC, representative.opid ASC LIMIT 1 ) LEFT JOIN LATERAL ( SELECT pr.room_name, pr.unit_name FROM c_property_roster pr WHERE pr.tenant_id = property.tenant_id AND pr.room_id = property.room_id AND pr.status = 'ACTIVE' ORDER BY pr.roster_id LIMIT 1 ) roster ON TRUE JOIN LATERAL ( SELECT supplier_quote.supplier_name, supplier_quote.quote_amount, supplier_quote.quote_summary, supplier_quote.attachment_id FROM t_repair_supplier_recommendation recommendation JOIN t_repair_supplier_quote supplier_quote ON supplier_quote.quote_id = recommendation.quote_id WHERE recommendation.work_order_id = decision.work_order_id AND recommendation.tenant_id = decision.tenant_id ORDER BY recommendation.create_time DESC, recommendation.recommendation_id DESC LIMIT 1 ) quote ON TRUE LEFT JOIN LATERAL ( SELECT online_entry.choice FROM t_repair_solitaire_entry online_entry WHERE online_entry.decision_id = decision.decision_id AND online_entry.owner_uid = property.uid AND online_entry.submission_channel = 'ONLINE' ORDER BY online_entry.update_time DESC, online_entry.entry_id DESC LIMIT 1 ) entry ON TRUE WHERE decision.decision_channel = 'ONLINE' AND decision.result = 'COLLECTING' AND work_order.status = 'LOCAL_DECISION_PENDING' AND (decision.scope_type = 'BUILDING' OR COALESCE(roster.unit_name, '默认单元') = decision.unit_name) AND decision.decision_id = #{decisionId}
AND EXISTS ( SELECT 1 FROM c_owner_property selected_property WHERE selected_property.opid = #{opid} AND selected_property.tenant_id = property.tenant_id AND selected_property.uid = property.uid AND selected_property.account_status = 1 )
GROUP BY decision.decision_id, work_order.work_order_id, work_order.order_no, work_order.title, work_order.location_text, work_order.survey_summary, decision.scope_label, quote.supplier_name, quote.quote_amount, quote.quote_summary, quote.attachment_id, entry.choice ORDER BY decision.decision_id DESC

SELECT room_id, owner_uid, choice, build_area, original_text
FROM t_repair_solitaire_entry
WHERE decision_id = #{decisionId}
  AND tenant_id = #{tenantId}
ORDER BY room_id

